package hcatalog.core.org.apache.hcatalog.cli.semanticanalysis;

final class CreateDatabaseHook extends HCatSemanticAnalyzerBase { String databaseName ; @ Override public ASTNode preAnalyze ( HiveSemanticAnalyzerHookContext context , ASTNode ast ) throws SemanticException { Hive db ; try { db = context . getHive ( ) ; } catch ( HiveException e ) { throw new SemanticException ( "Couldn't get Hive DB instance in semantic analysis phase." , e ) ; } int numCh = ast . getChildCount ( ) ; databaseName = BaseSemanticAnalyzer . getUnescapedName ( ( ASTNode ) ast . getChild ( 0 ) ) ; for ( int num = 1 ; num < numCh ; num ++ ) { ASTNode child = ( ASTNode ) ast . getChild ( num ) ; switch ( child . getToken ( ) . getType ( ) ) { case HiveParser . TOK_IFNOTEXISTS : try { List < String > dbs = db . getDatabasesByPattern ( databaseName ) ; if ( dbs != null && dbs . size ( ) > 0 ) { return ast ; } } catch ( HiveException e ) { throw new SemanticException ( e ) ; } break ; } } return ast ; } @ Override public void postAnalyze ( HiveSemanticAnalyzerHookContext context , List < Task < ? extends Serializable > > rootTasks ) throws SemanticException { context . getConf ( ) . set ( HCatConstants . HCAT_CREATE_DB_NAME , databaseName ) ; super . postAnalyze ( context , rootTasks ) ; } @ Override protected void authorizeDDLWork ( HiveSemanticAnalyzerHookContext context , Hive hive , DDLWork work ) throws HiveException { CreateDatabaseDesc createDb = work . getCreateDatabaseDesc ( ) ; if ( createDb != null ) { Database db = new Database ( createDb . getName ( ) , createDb . getComment ( ) , createDb . getLocationUri ( ) , createDb . getDatabaseProperties ( ) ) ; authorize ( db , Privilege . CREATE ) ; } } }